1	import { useState, type JSX } from 'react';
2	import type { TFunction } from 'i18next';
3	import { useTranslation } from 'react-i18next';
4	import type { Element } from '@bim-ai/core';
5	
6	import { planViewGraphicsMatrixRows, viewTemplateGraphicsMatrixRows } from '../plan/planProjection';
7	import { PlanViewGraphicsMatrix } from './PlanViewGraphicsMatrix';
8	import {
9	  SavedViewTagGraphicsAuthoring,
10	  SavedViewTemplateGraphicsAuthoring,
11	} from './savedViewTagGraphicsAuthoring';
12	
13	/**
14	 * Inspector parameter renderers — spec §13.
15	 *
16	 * Read-only field panels per element kind. The Apply / Reset footer is
17	 * left to the controlling Inspector component (which only shows it when
18	 * dirty=true). Numeric writes through the engine command pipeline land
19	 * separately when the redesigned palette gains drawing flow.
20	 */
21	
22	interface FieldRowProps {
23	  label: string;
24	  value: string;
25	  mono?: boolean;
26	}
27	
28	export function FieldRow({ label, value, mono }: FieldRowProps): JSX.Element {
29	  return (
30	    <div className="flex items-center justify-between gap-4 border-b border-border py-1.5 last:border-b-0">
31	      <span className="text-xs text-muted">{label}</span>
32	      <span className={['text-sm text-foreground', mono ? 'font-mono text-xs' : ''].join(' ')}>
33	        {value}
34	      </span>
35	    </div>
36	  );
37	}
38	
39	function fmtMm(value: number | null | undefined): string {
40	  if (value == null || !Number.isFinite(value)) return '—';
41	  if (Math.abs(value) >= 1000) return `${(value / 1000).toFixed(2)} m`;
42	  return `${value.toFixed(0)} mm`;
43	}
44	
45	export function InspectorPropertiesFor(el: Element, t: TFunction): JSX.Element {
46	  const f = (key: string) => t(`inspector.fields.${key}`);
47	  switch (el.kind) {
48	    case 'wall':
49	      return (
50	        <div>
51	          <FieldRow label={f('type')} value="Generic — wall" />
52	          <FieldRow label={f('thickness')} value={fmtMm(el.thicknessMm)} />
53	          <FieldRow label={f('height')} value={fmtMm(el.heightMm)} />
54	          <FieldRow label={f('level')} value={el.levelId} mono />
55	          <FieldRow label={f('start')} value={`${fmtMm(el.start.xMm)} · ${fmtMm(el.start.yMm)}`} mono />
56	          <FieldRow label={f('end')} value={`${fmtMm(el.end.xMm)} · ${fmtMm(el.end.yMm)}`} mono />
57	        </div>
58	      );
59	    case 'door':
60	      return (
61	        <div>
62	          <FieldRow label={f('family')} value={el.familyTypeId ?? 'Generic 900 × 2100'} mono />
63	          <FieldRow label={f('width')} value={fmtMm(el.widthMm)} />
64	          <FieldRow label={f('wall')} value={el.wallId} mono />
65	          <FieldRow label={f('alongT')} value={el.alongT.toFixed(3)} mono />
66	        </div>
67	      );
68	    case 'window':
69	      return (
70	        <div>
71	          <FieldRow label={f('family')} value={el.familyTypeId ?? 'Generic 1200 × 1500'} mono />
72	          <FieldRow label={f('width')} value={fmtMm(el.widthMm)} />
73	          <FieldRow label={f('height')} value={fmtMm(el.heightMm)} />
74	          <FieldRow label={f('sillHeight')} value={fmtMm(el.sillHeightMm)} />
75	          <FieldRow label={f('wall')} value={el.wallId} mono />
76	        </div>
77	      );
78	    case 'floor':
79	      return (
80	        <div>
81	          <FieldRow label={f('type')} value={el.floorTypeId ?? 'Generic 220 mm slab'} mono />
82	          <FieldRow label={f('thickness')} value={fmtMm(el.thicknessMm)} />
83	          <FieldRow label={f('structureThickness')} value={fmtMm(el.structureThicknessMm)} />
84	          <FieldRow label={f('finishThickness')} value={fmtMm(el.finishThicknessMm)} />
85	          <FieldRow label={f('level')} value={el.levelId} mono />
86	          <FieldRow label={f('boundaryPoints')} value={String(el.boundaryMm.length)} />
87	        </div>
88	      );
89	    case 'roof':
90	      return (
91	        <div>
92	          <FieldRow label={f('type')} value={el.roofTypeId ?? 'Generic gable'} mono />
93	          <FieldRow label={f('slope')} value={`${(el.slopeDeg ?? 0).toFixed(1)}°`} />
94	          <FieldRow label={f('overhang')} value={fmtMm(el.overhangMm)} />
95	          <FieldRow label={f('referenceLevel')} value={el.referenceLevelId} mono />
96	          <FieldRow label={f('footprintPoints')} value={String(el.footprintMm.length)} />
97	        </div>
98	      );
99	    case 'stair':
100	      return (
101	        <div>
102	          <FieldRow label={f('width')} value={fmtMm(el.widthMm)} />
103	          <FieldRow label={f('riser')} value={fmtMm(el.riserMm)} />
104	          <FieldRow label={f('tread')} value={fmtMm(el.treadMm)} />
105	          <FieldRow label={f('baseLevel')} value={el.baseLevelId} mono />
106	          <FieldRow label={f('topLevel')} value={el.topLevelId} mono />
107	        </div>
108	      );
109	    case 'room':
110	      return (
111	        <div>
112	          <FieldRow label={f('programme')} value={el.programmeCode ?? '—'} />
113	          <FieldRow label={f('department')} value={el.department ?? '—'} />
114	          <FieldRow label={f('function')} value={el.functionLabel ?? '—'} />
115	          <FieldRow label={f('finishSet')} value={el.finishSet ?? '—'} />
116	          <FieldRow label={f('level')} value={el.levelId} mono />
117	          <FieldRow label={f('outlinePoints')} value={String(el.outlineMm.length)} />
118	        </div>
119	      );
120	    case 'level':
121	      return (
122	        <div>
123	          <FieldRow label={f('elevation')} value={fmtMm(el.elevationMm)} />
124	          <FieldRow label={f('datumKind')} value={el.datumKind ?? '—'} mono />
125	        </div>
126	      );
127	    case 'section_cut':
128	      return (
129	        <div>
130	          <FieldRow
131	            label={f('lineStart')}
132	            value={`${fmtMm(el.lineStartMm.xMm)} · ${fmtMm(el.lineStartMm.yMm)}`}
133	            mono
134	          />
135	          <FieldRow
136	            label={f('lineEnd')}
137	            value={`${fmtMm(el.lineEndMm.xMm)} · ${fmtMm(el.lineEndMm.yMm)}`}
138	            mono
139	          />
140	          <FieldRow label={f('cropDepth')} value={fmtMm(el.cropDepthMm)} />
141	        </div>
142	      );
143	    case 'plan_view':
144	      return (
145	        <div>
146	          <FieldRow label={f('level')} value={el.levelId} mono />
147	          <FieldRow label={f('presentation')} value={el.planPresentation ?? 'default'} />
148	          {el.viewTemplateId ? <FieldRow label={f('template')} value={el.viewTemplateId} mono /> : null}
149	          {el.underlayLevelId ? <FieldRow label={f('underlay')} value={el.underlayLevelId} mono /> : null}
150	        </div>
151	      );
152	    case 'viewpoint':
153	      return (
154	        <div>
155	          <FieldRow label={f('name')} value={el.name} />
156	          <FieldRow label={f('id')} value={el.id} mono />
157	        </div>
158	      );
159	    case 'view_template':
160	      return (
161	        <div>
162	          <FieldRow label={f('scale')} value={el.scale} mono />
163	          {el.planDetailLevel ? <FieldRow label={f('detailLevel')} value={el.planDetailLevel} /> : null}
164	        </div>
165	      );
166	    default:
167	      return <p className="text-sm text-muted">{t('inspector.noParams', { kind: el.kind })}</p>;
168	  }
169	}
