171	export function InspectorConstraintsFor(el: Element, t: TFunction): JSX.Element {
172	  const f = (key: string) => t(`inspector.fields.${key}`);
173	  switch (el.kind) {
174	    case 'wall':
175	      return (
176	        <div>
