201	export function InspectorIdentityFor(el: Element, t: TFunction): JSX.Element {
202	  const f = (key: string) => t(`inspector.fields.${key}`);
203	  return (
204	    <div>
205	      <FieldRow label={f('kind')} value={el.kind} mono />
