214	export function InspectorGraphicsFor({
215	  el,
216	  elementsById,
217	  revision,
218	  onPersistProperty,
219	}: {
220	  el: Element;
221	  elementsById: Record<string, Element>;
222	  revision: number;
223	  onPersistProperty: (key: string, value: string) => void;
224	}): JSX.Element | null {
225	  if (el.kind === 'plan_view') {
226	    const rows = planViewGraphicsMatrixRows(elementsById, el.id);
227	    return (
228	      <div className="flex flex-col gap-4">
229	        <PlanViewGraphicsMatrix rows={rows} />
230	        <SavedViewTagGraphicsAuthoring
231	          variant="plan_view"
232	          selected={el as Extract<Element, { kind: 'plan_view' }>}
233	          revision={revision}
234	          elementsById={elementsById}
235	          onPersistProperty={onPersistProperty}
236	        />
237	      </div>
238	    );
239	  }
240	  if (el.kind === 'view_template') {
241	    const rows = viewTemplateGraphicsMatrixRows(elementsById, el.id);
242	    return (
243	      <div className="flex flex-col gap-4">
244	        <PlanViewGraphicsMatrix
245	          rows={rows}
246	          footnote="Template defaults — plan_view overrides these when linked."
247	        />
248	        <SavedViewTemplateGraphicsAuthoring
249	          selected={el as Extract<Element, { kind: 'view_template' }>}
250	          revision={revision}
251	          elementsById={elementsById}
252	          onPersistProperty={onPersistProperty}
253	        />
254	      </div>
255	    );
256	  }
257	  return null;
258	}
259	
260	const INPUT_CLS =
261	  'mt-1 w-full rounded border border-border bg-background px-2 py-1 font-mono text-[11px]';
262	const LABEL_CLS = 'block text-[10px] text-muted';
263	
264	/** Editable inspector for plan_view elements (Properties tab). */
265	export function InspectorPlanViewEditor({
266	  el,
267	  elementsById,
268	  revision,
269	  onPersistProperty,
270	}: {
271	  el: Extract<Element, { kind: 'plan_view' }>;
272	  elementsById: Record<string, Element>;
273	  revision: number;
274	  onPersistProperty: (key: string, value: string) => void;
275	}): JSX.Element {
276	  const levels = (Object.values(elementsById) as Element[]).filter(
277	    (e): e is Extract<Element, { kind: 'level' }> => e.kind === 'level',
278	  );
279	  const templates = (Object.values(elementsById) as Element[]).filter(
280	    (e): e is Extract<Element, { kind: 'view_template' }> => e.kind === 'view_template',
281	  );
282	
283	  const { t } = useTranslation();
284	  const pv = (key: string) => t(`inspector.planView.${key}`);
285	
286	  const [cropDraft, setCropDraft] = useState({
287	    minX: el.cropMinMm ? String(el.cropMinMm.xMm) : '',
288	    minY: el.cropMinMm ? String(el.cropMinMm.yMm) : '',
289	    maxX: el.cropMaxMm ? String(el.cropMaxMm.xMm) : '',
290	    maxY: el.cropMaxMm ? String(el.cropMaxMm.yMm) : '',
291	  });
292	
293	  return (
294	    <div className="space-y-2 text-[11px]">
295	      <label className={LABEL_CLS}>
296	        {pv('namePlaceholder')}
297	        <input
298	          className={INPUT_CLS}
299	          defaultValue={el.name}
300	          key={`pv-name-${el.id}-${el.name}-${revision}`}
301	          onBlur={(e) => {
302	            const v = e.target.value.trim();
303	            if (!v || v === el.name) return;
304	            onPersistProperty('name', v);
305	          }}
306	        />
307	      </label>
308	
309	      <label className={LABEL_CLS}>
310	        {pv('planPresentation')}
311	        <select
312	          className={INPUT_CLS}
313	          value={el.planPresentation ?? 'default'}
314	          onChange={(e) => onPersistProperty('planPresentation', e.target.value)}
315	        >
316	          <option value="default">{pv('neutralPresentation')}</option>
317	          <option value="opening_focus">{pv('openingFocus')}</option>
318	          <option value="room_scheme">{pv('roomScheme')}</option>
319	        </select>
320	      </label>
321	
322	      <label className={LABEL_CLS}>
323	        {pv('underlayLevel')}
324	        <select
325	          className={INPUT_CLS}
326	          value={el.underlayLevelId && levels.some((l) => l.id === el.underlayLevelId) ? el.underlayLevelId : ''}
327	          onChange={(e) => onPersistProperty('underlayLevelId', e.target.value)}
328	        >
329	          <option value="">{pv('none')}</option>
330	          {levels.map((l) => (
331	            <option key={l.id} value={l.id}>{l.name}</option>
332	          ))}
333	        </select>
334	      </label>
335	
336	      {templates.length > 0 ? (
337	        <>
338	          <label className={LABEL_CLS}>
339	            {pv('viewTemplateLink')}
340	            <select
341	              className={INPUT_CLS}
342	              value={el.viewTemplateId && templates.some((tmpl) => tmpl.id === el.viewTemplateId) ? el.viewTemplateId : ''}
343	              onChange={(e) => onPersistProperty('viewTemplateId', e.target.value)}
344	            >
345	              <option value="">{pv('none')}</option>
346	              {templates.map((tmpl) => (
347	                <option key={tmpl.id} value={tmpl.id}>{tmpl.name}</option>
348	              ))}
349	            </select>
350	          </label>
351	          <label className={LABEL_CLS}>
352	            {pv('applyTemplate')}
353	            <select
354	              className={INPUT_CLS}
355	              value=""
356	              onChange={(e) => {
357	                const tid = e.target.value;
358	                if (!tid) return;
359	                onPersistProperty('__applyTemplate__', JSON.stringify({ planViewId: el.id, templateId: tid }));
360	              }}
361	            >
362	              <option value="">{pv('selectToApply')}</option>
363	              {templates.map((tmpl) => (
364	                <option key={tmpl.id} value={tmpl.id}>{tmpl.name}</option>
365	              ))}
366	            </select>
367	          </label>
368	        </>
369	      ) : null}
370	
371	      <div className="border-t border-border pt-2 space-y-2">
372	        <div className="font-semibold text-muted">{pv('crop')}</div>
373	        <div className="grid grid-cols-2 gap-2">
374	          {(['minX', 'minY', 'maxX', 'maxY'] as const).map((k) => (
375	            <label key={k} className={LABEL_CLS}>
376	              {k}
377	              <input
378	                className={INPUT_CLS}
379	                value={cropDraft[k]}
380	                onChange={(e) => setCropDraft((d) => ({ ...d, [k]: e.target.value }))}
381	              />
382	            </label>
383	          ))}
384	        </div>
385	        <div className="flex gap-2">
386	          <button
387	            type="button"
388	            className="flex-1 rounded border border-border bg-background px-2 py-1 text-[10px] hover:bg-surface-strong"
389	            onClick={() => {
390	              const nx = Number(cropDraft.minX), ny = Number(cropDraft.minY);
391	              const xx = Number(cropDraft.maxX), xy = Number(cropDraft.maxY);
392	              if (![nx, ny, xx, xy].every(Number.isFinite)) return;
393	              onPersistProperty('cropMinMm', JSON.stringify({ xMm: nx, yMm: ny }));
394	              onPersistProperty('cropMaxMm', JSON.stringify({ xMm: xx, yMm: xy }));
395	            }}
396	          >
397	            {pv('applyCrop')}
398	          </button>
399	          <button
400	            type="button"
401	            className="flex-1 rounded border border-border bg-background px-2 py-1 text-[10px] hover:bg-surface-strong"
402	            onClick={() => {
403	              onPersistProperty('cropMinMm', '');
404	              onPersistProperty('cropMaxMm', '');
405	              setCropDraft({ minX: '', minY: '', maxX: '', maxY: '' });
406	            }}
407	          >
408	            {pv('clearCrop')}
409	          </button>
410	        </div>
411	      </div>
412	
413	      <div className="border-t border-border pt-2 space-y-2">
414	        <div className="font-semibold text-muted">{pv('viewRange')}</div>
415	        {(
416	          [
417	            { key: 'viewRangeBottomMm', label: pv('rangeBottom'), val: el.viewRangeBottomMm },
418	            { key: 'viewRangeTopMm', label: pv('rangeTop'), val: el.viewRangeTopMm },
419	            { key: 'cutPlaneOffsetMm', label: pv('cutPlaneOffset'), val: el.cutPlaneOffsetMm },
420	          ] as { key: string; label: string; val: number | null | undefined }[]
421	        ).map(({ key, label, val }) => (
422	          <label key={key} className={LABEL_CLS}>
423	            {label}
424	            <input
425	              className={INPUT_CLS}
426	              defaultValue={val == null ? '' : String(val)}
427	              key={`${key}-${el.id}-${val ?? 'null'}-${revision}`}
428	              placeholder={pv('emptyClearsPlaceholder')}
429	              inputMode="decimal"
430	              onBlur={(e) => onPersistProperty(key, e.target.value.trim())}
431	            />
432	          </label>
433	        ))}
434	      </div>
435	    </div>
436	  );
437	}
