439	/** Editable inspector for room elements (Properties tab). */
440	export function InspectorRoomEditor({
441	  el,
442	  revision,
443	  onPersistProperty,
444	}: {
445	  el: Extract<Element, { kind: 'room' }>;
446	  revision: number;
447	  onPersistProperty: (key: string, value: string) => void;
448	}): JSX.Element {
449	  const { t } = useTranslation();
450	  const f = (key: string) => t(`inspector.fields.${key}`);
451	  const r = (key: string) => t(`inspector.room.${key}`);
452	  const fields: { key: string; label: string; val: string | null | undefined; inputMode?: string }[] = [
453	    { key: 'name', label: f('name'), val: el.name },
454	    { key: 'programmeCode', label: r('programmeCode'), val: el.programmeCode },
455	    { key: 'department', label: f('department'), val: el.department },
456	    { key: 'functionLabel', label: r('functionLabel'), val: el.functionLabel },
457	    { key: 'finishSet', label: f('finishSet'), val: el.finishSet },
458	  ];
459	
460	  return (
461	    <div className="space-y-2 text-[11px]">
462	      {fields.map(({ key, label, val }) => (
463	        <label key={key} className={LABEL_CLS}>
464	          {label}
465	          <input
466	            className={INPUT_CLS}
467	            defaultValue={val ?? ''}
468	            key={`rm-${key}-${el.id}-${val ?? ''}-${revision}`}
469	            onBlur={(e) => {
470	              const v = e.target.value.trim();
471	              if (key === 'name' && (!v || v === val)) return;
472	              onPersistProperty(key, v);
473	            }}
474	          />
475	        </label>
476	      ))}
477	      <label className={LABEL_CLS}>
478	        {r('targetArea')}
479	        <input
480	          className={INPUT_CLS}
481	          defaultValue={el.targetAreaM2 == null ? '' : String(el.targetAreaM2)}
482	          key={`rm-tgt-${el.id}-${el.targetAreaM2 ?? 'x'}-${revision}`}
483	          placeholder={r('optional')}
484	          inputMode="decimal"
485	          onBlur={(e) => onPersistProperty('targetAreaM2', e.target.value.trim())}
486	        />
487	      </label>
488	      <FieldRow label={f('level')} value={el.levelId} mono />
489	      <FieldRow label={f('outlinePoints')} value={String(el.outlineMm.length)} />
490	    </div>
491	  );
492	}
